import React, { useEffect, useState } from "react";
import {
  Box,
  Typography,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Button,
  CircularProgress,
  Alert,
} from "@mui/material";
import axios from "axios";

const AdminDashboard = () => {
  const [riders, setRiders] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  // Fetch riders
  const fetchRiders = async () => {
    try {
      setLoading(true);
      const token = localStorage.getItem("token"); // admin JWT
      const res = await axios.get("/api/rider/all", {
        headers: { Authorization: `Bearer ${token}` },
      });
      setRiders(res.data.riders || []);
      setError("");
    } catch (err) {
      console.error("❌ Fetch riders error:", err);
      setError("Failed to fetch riders");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchRiders();
  }, []);

  // Approve Rider
  const handleApprove = async (id) => {
    try {
      const token = localStorage.getItem("token");
      await axios.post(`/api/rider/approve/${id}`, {}, {
        headers: { Authorization: `Bearer ${token}` },
      });
      fetchRiders();
    } catch (err) {
      console.error("❌ Approve error:", err);
      setError("Failed to approve rider");
    }
  };

  // Reject Rider
  const handleReject = async (id) => {
    try {
      const token = localStorage.getItem("token");
      await axios.post(`/api/rider/reject/${id}`, {}, {
        headers: { Authorization: `Bearer ${token}` },
      });
      fetchRiders();
    } catch (err) {
      console.error("❌ Reject error:", err);
      setError("Failed to reject rider");
    }
  };

  return (
    <Box p={4}>
      <Typography variant="h4" gutterBottom>
        Rider App - Admin Dashboard
      </Typography>

      {loading && <CircularProgress />}
      {error && <Alert severity="error">{error}</Alert>}

      <TableContainer component={Paper} sx={{ mt: 3 }}>
        <Table>
          <TableHead>
            <TableRow>
              <TableCell><b>Full Name</b></TableCell>
              <TableCell><b>Email</b></TableCell>
              <TableCell><b>Mobile</b></TableCell>
              <TableCell><b>Status</b></TableCell>
              <TableCell><b>Actions</b></TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {riders.map((rider) => (
              <TableRow key={rider._id}>
                <TableCell>{rider.fullName}</TableCell>
                <TableCell>{rider.email}</TableCell>
                <TableCell>{rider.mobile}</TableCell>
                <TableCell>{rider.status}</TableCell>
                <TableCell>
                  {rider.status === "pending" && (
                    <>
                      <Button
                        variant="contained"
                        color="success"
                        size="small"
                        sx={{ mr: 1 }}
                        onClick={() => handleApprove(rider._id)}
                      >
                        Approve
                      </Button>
                      <Button
                        variant="contained"
                        color="error"
                        size="small"
                        onClick={() => handleReject(rider._id)}
                      >
                        Reject
                      </Button>
                    </>
                  )}
                  {rider.status === "approved_pending_otp" && (
                    <Typography color="warning.main">
                      Waiting for OTP verification
                    </Typography>
                  )}
                  {rider.status === "active" && (
                    <Typography color="success.main">Active</Typography>
                  )}
                  {rider.status === "rejected" && (
                    <Typography color="error.main">Rejected</Typography>
                  )}
                </TableCell>
              </TableRow>
            ))}
            {riders.length === 0 && !loading && (
              <TableRow>
                <TableCell colSpan={5} align="center">
                  No riders found
                </TableCell>
              </TableRow>
            )}
          </TableBody>
        </Table>
      </TableContainer>
    </Box>
  );
};

export default AdminDashboard;
